import{_ as a,c as i,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Inicio Rápido en AI App Factory: desde la instalación hasta ejecutar tu primera aplicación | agent-app-factory","description":"Aprende a iniciar rápidamente AI App Factory, desde la instalación y configuración de la herramienta CLI hasta comprender el principio de funcionamiento de la tubería de 7 etapas. Domina la inicialización de proyectos y comienza tu viaje de generación de la primera aplicación. Este capítulo incluye cuatro cursos básicos: inicio rápido, instalación y configuración, inicialización del proyecto y descripción general de la tubería, ayudándote a comprender completamente el proceso automatizado de extremo a extremo desde la idea hasta la aplicación ejecutable.","frontmatter":{"title":"Inicio Rápido en AI App Factory: desde la instalación hasta ejecutar tu primera aplicación | agent-app-factory","sidebarTitle":"Inicio","subtitle":"Inicio","description":"Aprende a iniciar rápidamente AI App Factory, desde la instalación y configuración de la herramienta CLI hasta comprender el principio de funcionamiento de la tubería de 7 etapas. Domina la inicialización de proyectos y comienza tu viaje de generación de la primera aplicación. Este capítulo incluye cuatro cursos básicos: inicio rápido, instalación y configuración, inicialización del proyecto y descripción general de la tubería, ayudándote a comprender completamente el proceso automatizado de extremo a extremo desde la idea hasta la aplicación ejecutable.","order":10},"headers":[],"relativePath":"es/hyz1992/agent-app-factory/start/index.md","filePath":"es/hyz1992/agent-app-factory/start/index.md"}'),n={name:"es/hyz1992/agent-app-factory/start/index.md"};function t(l,e,c,d,s,p){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="inicio" tabindex="-1">Inicio <a class="header-anchor" href="#inicio" aria-label="Permalink to &quot;Inicio&quot;">​</a></h1><p>Este capítulo te ayuda a iniciar rápidamente con AI App Factory, comprender el valor central, instalar y configurar las herramientas, y comprender el principio de funcionamiento de la tubería de 7 etapas, preparándote para generar tu primera aplicación.</p><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><p>Se recomienda seguir el siguiente orden para estudiar el contenido de este capítulo:</p><h3 id="_1-inicio-rapido-desde-la-idea-hasta-la-aplicacion" tabindex="-1">1. <a href="./../getting-started/">Inicio Rápido: desde la idea hasta la aplicación</a> <a class="header-anchor" href="#_1-inicio-rapido-desde-la-idea-hasta-la-aplicacion" aria-label="Permalink to &quot;1. [Inicio Rápido: desde la idea hasta la aplicación](../getting-started/)&quot;">​</a></h3><p>Comprende el valor central y los requisitos previos de AI App Factory, y experimenta el proceso de extremo a extremo desde la idea hasta la aplicación a través de un caso completo.</p><ul><li>Comprender el mecanismo de colaboración multi-agente basado en puntos de control</li><li>Conocer el flujo de trabajo completo de la tubería de 7 etapas</li><li>Dominar las técnicas para proporcionar descripciones claras del producto</li></ul><h3 id="_2-instalacion-y-configuracion" tabindex="-1">2. <a href="./../installation/">Instalación y Configuración</a> <a class="header-anchor" href="#_2-instalacion-y-configuracion" aria-label="Permalink to &quot;2. [Instalación y Configuración](../installation/)&quot;">​</a></h3><p>Instala la herramienta CLI globalmente, configura los asistentes de IA (Claude Code/OpenCode) y el entorno relacionado.</p><ul><li>Instalar agent-app-factory globalmente usando npm</li><li>Configurar Claude Code u OpenCode</li><li>Verificar que la instalación sea exitosa</li></ul><h3 id="_3-inicializar-proyecto-factory" tabindex="-1">3. <a href="./../init-project/">Inicializar Proyecto Factory</a> <a class="header-anchor" href="#_3-inicializar-proyecto-factory" aria-label="Permalink to &quot;3. [Inicializar Proyecto Factory](../init-project/)&quot;">​</a></h3><p>Usa el comando <code>factory init</code> para inicializar el directorio, y comprender la estructura del proyecto generado y los archivos de configuración.</p><ul><li>Ejecutar el comando de inicialización del proyecto</li><li>Comprender la estructura del directorio del proyecto y los archivos de configuración</li><li>Preparar la entrada de la idea del producto</li></ul><h3 id="_4-descripcion-general-de-la-tuberia-de-7-etapas" tabindex="-1">4. <a href="./../pipeline-overview/">Descripción General de la Tubería de 7 Etapas</a> <a class="header-anchor" href="#_4-descripcion-general-de-la-tuberia-de-7-etapas" aria-label="Permalink to &quot;4. [Descripción General de la Tubería de 7 Etapas](../pipeline-overview/)&quot;">​</a></h3><p>Comprende profundamente el proceso completo de la tubería desde Bootstrap hasta Preview, las entradas y salidas de cada etapa, y el mecanismo de puntos de control.</p><ul><li>Comprender los objetivos y productos de las 7 etapas</li><li>Dominar el mecanismo de puntos de control y el proceso de confirmación manual</li><li>Aprender a controlar la ejecución de la tubería</li></ul><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><p>Antes de comenzar a estudiar este capítulo, necesitas:</p><div class="warning custom-block"><p class="custom-block-title">Requisitos Previos</p><ol><li><strong>Entorno de Node.js</strong>: Node.js v18 o versión superior ya instalado</li><li><strong>Asistente de Programación de IA</strong>: Debes configurar una de las siguientes herramientas <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> (recomendado) ⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> u otros asistentes de IA que admitan el modo Agent</li></ul></li><li><strong>Operaciones Básicas de Línea de Comandos</strong>: Poder ejecutar comandos usando la terminal</li></ol></div><h2 id="siguiente-paso" tabindex="-1">Siguiente Paso <a class="header-anchor" href="#siguiente-paso" aria-label="Permalink to &quot;Siguiente Paso&quot;">​</a></h2><p>Después de completar el estudio de este capítulo, dominarás:</p><ul><li>✅ El principio de funcionamiento central de AI App Factory</li><li>✅ La instalación y configuración de la herramienta CLI</li><li>✅ La inicialización del proyecto y la comprensión de la estructura</li><li>✅ El proceso completo de la tubería de 7 etapas</li></ul><p>A continuación, se recomienda estudiar el capítulo <strong><a href="./../../platforms/">Plataformas e Integración</a></strong> para comprender cómo ejecutar la tubería en diferentes asistentes de IA.</p>',23)])])}const h=a(n,[["render",t]]);export{m as __pageData,h as default};
